public class Decorator {
    interface TextTransform { String transform(String s); }
    static class Upper implements TextTransform {
        public String transform(String s) { return s.toUpperCase(); }
    }
    static class Exclaim implements TextTransform {
        TextTransform inner;
        String suffix = "!";
        Exclaim(TextTransform t) { inner = t; }
        public String transform(String s) {
            suffix += "!";   // bug: suffix grows each call
            return inner.transform(s) + suffix;
        }
    }
    public static void main(String[] args) {
        TextTransform t = new Exclaim(new Upper());
        System.out.println(t.transform("hi"));
        System.out.println(t.transform("bye"));
    }
}
